mapper.select:
select
    sum(amount) amount
FROM
    agent_deposit_subordinates
where 1 = 1
and site_code=#{vo.siteCode}

    AND order_no = #{vo.orderNo}


    AND agent_account = #{vo.agentAccount}


    AND deposit_time  >=  #{vo.startTime}


    AND deposit_time  <=  #{vo.endTime}


    AND amount  >=  #{vo.amountMin}


    AND amount  <=  #{vo.amountMax}

select
    count(1)
FROM
    agent_deposit_subordinates
where 1 = 1
and site_code=#{vo.siteCode}

    AND order_no = #{vo.orderNo}


    AND agent_account = #{vo.agentAccount}


    AND deposit_time  >=  #{vo.startTime}


    AND deposit_time  <=  #{vo.endTime}


    AND amount  >=  #{vo.amountMin}


    AND amount  <=  #{vo.amountMax}

select sum(amount) as amount
from agent_deposit_subordinates s
        left join agent_info a on a.agent_account = s.agent_account
where s.deposit_time between #{beginTime} and #{endTime}
        and s.deposit_subordinates_type=#{subordType}
        and a.agent_type in (1,2)

select s.agent_account
from agent_deposit_subordinates s
         left join agent_info a on a.agent_account = s.agent_account
where s.deposit_time between #{beginTime} and #{endTime}
          and s.deposit_subordinates_type=#{subordType}
          and a.agent_type in (1,2)

select s.user_account AS account, s.deposit_time AS distributeTime, s.remark AS remark, a.coin_from AS beforeDistributionAmount, a.coin_to AS afterDistributionAmount, a.coin_amount AS distributionAmount, s.running_water_multiple AS turnoverMultiple, a.wallet_type AS walletType from agent_deposit_subordinates s left join agent_coin_record a on a.order_no = s.order_no
and s.user_account = #{vo.searchAccount}
and s.site_code = #{vo.siteCode} and s.agent_account = #{vo.agentAccount} and s.deposit_time >= #{vo.startTime} and s.deposit_time <= #{vo.endTime}
order by s.deposit_time desc

select
IFNULL(sum(amount),0) as amount,
agent_account as agentAccount,
currency_code as currency
from agent_deposit_subordinates
where 1=1
and site_code=#{vo.siteCode}
and deposit_time  >=   #{vo.startTime}
and deposit_time  <=  #{vo.endTime}

    AND agent_account in

        #{value}



    AND agent_id in

        #{value}



    and currency_code = #{vo.currency}

group by agent_account,currency_code

SELECT site_code , #{vo.startTime} date, currency_code as currency, count(1) as storedMembersLimitTimes, count(distinct user_id) as storedMembersLimitPeopleNumber, sum(amount) as storedMembersLimit from agent_deposit_subordinates
AND `deposit_time` >= #{vo.startTime}
AND `deposit_time` <= #{vo.endTime}
group by site_code ,currency_code
